package com.example.dataproc.transfer;

import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.stub.StreamObserver;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Iterator;
import java.util.UUID;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;

public final class TransferClient {
    private final ManagedChannel channel;
    private final TransferServiceGrpc.TransferServiceStub async;
    private final TransferServiceGrpc.TransferServiceBlockingStub blocking;

    public TransferClient(String host, int port) {
        int maxInbound = Integer.parseInt(System.getProperty("grpc.maxInboundMessageSize", String.valueOf(Integer.MAX_VALUE)));
        this.channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .maxInboundMessageSize(maxInbound)
                .build();
        this.async = TransferServiceGrpc.newStub(channel);
        this.blocking = TransferServiceGrpc.newBlockingStub(channel);
    }

    public void shutdown() {
        channel.shutdown();
    }

    public String uploadFile(Path file, int chunkSize) throws Exception {
        String uploadId = UUID.randomUUID().toString();
        CountDownLatch done = new CountDownLatch(1);
        final String[] result = new String[1];

        StreamObserver<UploadResponse> respObs = new StreamObserver<>() {
            @Override
            public void onNext(UploadResponse value) {
                result[0] = value.getUploadId();
            }

            @Override
            public void onError(Throwable t) {
                done.countDown();
            }

            @Override
            public void onCompleted() {
                done.countDown();
            }
        };

        StreamObserver<UploadRequest> reqObs = async.upload(respObs);

        byte[] buf = new byte[Math.max(1, chunkSize)];
        try (var in = Files.newInputStream(file)) {
            int n;
            while ((n = in.read(buf)) >= 0) {
                if (n == 0) continue;
                reqObs.onNext(UploadRequest.newBuilder()
                        .setUploadId(uploadId)
                        .setFileName(file.getFileName().toString())
                        .setData(com.google.protobuf.ByteString.copyFrom(buf, 0, n))
                        .setFinish(false)
                        .build());
            }
        }

        reqObs.onNext(UploadRequest.newBuilder()
                .setUploadId(uploadId)
                .setFileName(file.getFileName().toString())
                .setData(com.google.protobuf.ByteString.EMPTY)
                .setFinish(true)
                .build());
        reqObs.onCompleted();

        done.await(60, TimeUnit.SECONDS);
        return result[0] != null ? result[0] : uploadId;
    }

    public void downloadToFile(String fileId, Path out, int chunkSize) throws Exception {
        Iterator<DownloadChunk> it = blocking.download(DownloadRequest.newBuilder()
                .setFileId(fileId)
                .setChunkSize(chunkSize)
                .build());

        Files.createDirectories(out.getParent() == null ? Path.of(".") : out.getParent());
        try (var os = Files.newOutputStream(out)) {
            while (it.hasNext()) {
                DownloadChunk c = it.next();
                if (!c.getData().isEmpty()) os.write(c.getData().toByteArray());
                if (c.getFinish()) break;
            }
        }
    }

    public void bidiEcho(byte[] payload) throws Exception {
        CountDownLatch done = new CountDownLatch(1);

        StreamObserver<TransferMessage> resp = new StreamObserver<>() {
            @Override
            public void onNext(TransferMessage value) {
            }

            @Override
            public void onError(Throwable t) {
                done.countDown();
            }

            @Override
            public void onCompleted() {
                done.countDown();
            }
        };

        StreamObserver<TransferMessage> req = async.transfer(resp);
        req.onNext(TransferMessage.newBuilder()
                .setStreamId(UUID.randomUUID().toString())
                .setType("ECHO")
                .setPayload(com.google.protobuf.ByteString.copyFrom(payload))
                .setFinish(false)
                .build());
        req.onNext(TransferMessage.newBuilder()
                .setStreamId(UUID.randomUUID().toString())
                .setType("PING")
                .setPayload(com.google.protobuf.ByteString.copyFromUtf8("ping"))
                .setFinish(false)
                .build());
        req.onNext(TransferMessage.newBuilder()
                .setStreamId(UUID.randomUUID().toString())
                .setType("ACK")
                .setPayload(com.google.protobuf.ByteString.EMPTY)
                .setFinish(true)
                .build());
        req.onCompleted();

        done.await(30, TimeUnit.SECONDS);
    }
}